class Solution {
    public int findTheLongestBalancedSubstring(String s) {
        int maxLength = 0;
        for (int i = 0; i < s.length(); i++) {
            int zeros = 0, ones = 0;
            for (int j = i; j < s.length(); j++) {
                if (s.charAt(j) == '0') {
                    zeros++;
                } else {
                    ones++;
                }
                if (zeros == ones) {
                    maxLength = Math.max(maxLength, ones + zeros);
                } else if (ones > zeros) {
                    break;
                }
            }
        }
        return maxLength;
    }
}
